import{_ as o,c as a,o as t,ai as n}from"./chunks/framework.CObI3_Hx.js";const f=JSON.parse('{"title":"NeoNephos held on-site Governing Board Workshop in May","description":"","frontmatter":{"title":"NeoNephos held on-site Governing Board Workshop in May","date":"2026-05-07","banner":"assets/blog/20260507_governing_board_workshop_neonepho_banner.svg","authors":["neonephos-team"],"tags":["2026","news"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"BlogEntryThemeComponent"},"headers":[],"relativePath":"blog/20260507_governing_board_workshop.md","filePath":"blog/20260507_governing_board_workshop.md"}'),r={name:"blog/20260507_governing_board_workshop.md"};function i(s,e,h,d,l,p){return t(),a("div",null,e[0]||(e[0]=[n('<p>On the 7th of May 2026 the NeoNephos Governing Board again held an on-site workshop at SAP in Walldorf. The all-day get-together was filled with presentations, discussions, good food and sometimes contentious but always friendly debates. Everyone shared the goal of wanting to make the foundation better. What emerged was a concrete vision about the future of NeoNephos in the form of a roadmap, which we are proud to present further in this post.</p><h2 id="the-q2-2026-q1-2027-neonephos-roadmap" tabindex="-1">The Q2 2026 - Q1 2027 NeoNephos Roadmap <a class="header-anchor" href="#the-q2-2026-q1-2027-neonephos-roadmap" aria-label="Permalink to &quot;The Q2 2026 - Q1 2027 NeoNephos Roadmap&quot;">​</a></h2><img src="https://example.com/image.jpg" alt="Roadmap of NeoNephos 2026-2027" width="500"><p>Let&#39;s dive throug all the points in order.</p><h3 id="onboard-first-neonephos-ambassador" tabindex="-1">Onboard First NeoNephos Ambassador <a class="header-anchor" href="#onboard-first-neonephos-ambassador" aria-label="Permalink to &quot;Onboard First NeoNephos Ambassador&quot;">​</a></h3><p>While applications to the ambassador program are still private as of the time of this writing, behind the scenes the first ambassadors are evaluated. This first set of people have already proven their value to the NeoNephos Foundation in the past and serve as good first candidates to start the ambassador program. We hope to officially announce the onboarding of the first Ambassador in Q2 2026.</p><h3 id="finalize-project-lifecycle" tabindex="-1">Finalize Project Lifecycle <a class="header-anchor" href="#finalize-project-lifecycle" aria-label="Permalink to &quot;Finalize Project Lifecycle&quot;">​</a></h3><p>The <a href="https://github.com/neonephos/guidelines-development/blob/main/lifecycle-policy/project-lifecycle-policy.md" target="_blank" rel="noreferrer">Project Lifecycle policy</a> is one of the most essential documents in the foundation as it sets the conditions, expectations and benefits levied upon prospective and incumbent projects. As stated in the roadmap, we hope to finalize it soon. The development of this document is public and you can contribute <a href="https://github.com/neonephos/guidelines-development/blob/main/lifecycle-policy/project-lifecycle-policy.md" target="_blank" rel="noreferrer">here</a>.</p><h3 id="introduce-new-neonephos-logomark" tabindex="-1">Introduce New NeoNephos Logomark <a class="header-anchor" href="#introduce-new-neonephos-logomark" aria-label="Permalink to &quot;Introduce New NeoNephos Logomark&quot;">​</a></h3><p>NeoNephos lacks a clear logomark yet. Several designs are in the pipeline and we are confident to introduce one soon.</p><h3 id="participate-at-kubecon-cloudnativecon-india" tabindex="-1">Participate at KubeCon+CloudNativeCon India <a class="header-anchor" href="#participate-at-kubecon-cloudnativecon-india" aria-label="Permalink to &quot;Participate at KubeCon+CloudNativeCon India&quot;">​</a></h3><p>The benefits of sovereignty extend world-wide. Therefore, we are present at the KubeCon+CloudNativeCon India with <a href="https://kccncind2026.sched.com/event/2IW1x/kubernetes-plane-aerodynamics-breaking-the-architectural-sound-barrier-vasu-chandrasekhara-neonephos-stefan-schimanski-nvidia?iframe=yes&amp;w=100%25&amp;sidebar=yes&amp;bg=no" target="_blank" rel="noreferrer">a talk</a>.</p><h3 id="plan-events-2026-2026" tabindex="-1">Plan Events 2026/2026 <a class="header-anchor" href="#plan-events-2026-2026" aria-label="Permalink to &quot;Plan Events 2026/2026&quot;">​</a></h3><p>We have to scope much further ahead and let you know a long time beforehand, where we intend to be. That is why we are improving on the process on selecting events for attendance. You know an interesting event we should attend? Let&#39;s chat on Zulip!</p>',14)]))}const m=o(r,[["render",i]]);export{f as __pageData,m as default};
